int search(int stat,int sum,int dep){

	if(dep==n)	return memo[stat][sum]=(s==sum);

	if(~memo[stat][sum])	return memo[stat][sum];

	if(sum>s)	return 0;



	int cnt=0;

	for(int i=0;i<10;i++){

		if((stat&(1<<i))==0){

			stat|=1<<i;

			cnt+=search(stat,sum+i*(n-dep),dep+1);

			stat&=~(1<<i);

		}

	}

	return memo[stat][sum]=cnt;

}



